css:
* { margin: 0; padding: 0; box-sizing: border-box; font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; }
body { background: #070b18; color: white; overflow-x: hidden; }
.navbar { display: flex; align-items: center; justify-content: space-between; padding: 22px 60px; }
.brand { font-size: 20px; font-weight: 800; }
.nav-links { display: flex; gap: 32px; }
.nav-links a { color: rgba(255,255,255,0.65); text-decoration: none; font-size: 14px; font-weight: 600; }
.nav-btn { background: linear-gradient(135deg, #6366f1, #818cf8); border: none; color: white; padding: 11px 26px; border-radius: 999px; font-size: 13.5px; font-weight: 700; cursor: pointer; }
.hero { display: flex; align-items: center; justify-content: space-between; padding: 60px 60px 100px; gap: 60px; flex-wrap: wrap; position: relative; }
.hero-left { max-width: 520px; }
.badge { display: inline-block; background: rgba(99,102,241,0.15); color: #818cf8; font-size: 12.5px; font-weight: 700; padding: 6px 16px; border-radius: 999px; margin-bottom: 20px; }
.hero-left h1 { font-size: 54px; font-weight: 800; line-height: 1.15; margin-bottom: 18px; }
.hero-left h1 span { background: linear-gradient(135deg, #818cf8, #c084fc); -webkit-background-clip: text; background-clip: text; color: transparent; }
.hero-left p { color: rgba(255,255,255,0.55); font-size: 16px; line-height: 1.7; margin-bottom: 28px; }
.store-buttons { display: flex; gap: 12px; margin-bottom: 36px; flex-wrap: wrap; }
.store-btn { display: flex; align-items: center; gap: 10px; background: white; color: #0a0e1a; border: none; padding: 13px 24px; border-radius: 12px; font-size: 14px; font-weight: 700; cursor: pointer; }
.store-btn.light { background: rgba(255,255,255,0.12); color: white; border: 1px solid rgba(255,255,255,0.2); }
.store-icon { width: 18px; height: 18px; border-radius: 4px; background: linear-gradient(135deg, #6366f1, #c084fc); }
.hero-stats { display: flex; gap: 36px; }
.stat { display: flex; flex-direction: column; }
.stat strong { font-size: 22px; font-weight: 800; }
.stat span { font-size: 12.5px; color: rgba(255,255,255,0.4); }
.hero-right { position: relative; flex-shrink: 0; }
.phone-mock { width: 260px; height: 520px; background: #14101f; border: 8px solid #1f1a2e; border-radius: 40px; padding: 28px 18px; position: relative; box-shadow: 0 40px 100px rgba(99,102,241,0.25); }
.phone-notch { position: absolute; top: 14px; left: 50%; transform: translateX(-50%); width: 80px; height: 18px; background: #1f1a2e; border-radius: 999px; }
.app-header { color: white; font-size: 20px; font-weight: 800; margin: 24px 0 18px; }
.app-card { background: rgba(255,255,255,0.05); border-radius: 14px; padding: 16px; margin-bottom: 12px; display: flex; align-items: center; gap: 12px; font-size: 14px; color: rgba(255,255,255,0.8); }
.app-card.active { background: linear-gradient(135deg, rgba(99,102,241,0.25), rgba(192,132,252,0.25)); border: 1px solid rgba(129,140,248,0.4); }
.float-card { position: absolute; background: rgba(255,255,255,0.08); border: 1px solid rgba(255,255,255,0.15); backdrop-filter: blur(10px); padding: 12px 18px; border-radius: 14px; font-size: 13px; font-weight: 700; }
.float-1 { top: 80px; right: -10px; }
.float-2 { bottom: 100px; left: -40px; }
.features { padding: 60px; text-align: center; }
.features h2 { font-size: 36px; font-weight: 800; margin-bottom: 48px; }
.feature-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(220px, 1fr)); gap: 24px; max-width: 1100px; margin: 0 auto; }
.feature { background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.07); border-radius: 18px; padding: 28px; text-align: left; }
.ficon { font-size: 30px; margin-bottom: 14px; }
.feature h3 { font-size: 17px; font-weight: 700; margin-bottom: 8px; }
.feature p { color: rgba(255,255,255,0.5); font-size: 13.5px; line-height: 1.6; }
.cta { text-align: center; padding: 80px 60px; background: linear-gradient(135deg, rgba(99,102,241,0.12), rgba(192,132,252,0.12)); }
.cta h2 { font-size: 30px; font-weight: 800; margin-bottom: 28px; }
.cta .store-buttons { justify-content: center; }
@media (max-width: 900px) { .hero { padding: 40px 24px; } .hero-left h1 { font-size: 38px; } .features, .cta { padding: 50px 24px; } }
